        int w1_eb = (w1_bits >> 1) & 0x3;
        int w1_mb = w1_bits & 1;
        float w1_base = (w1_eb == 0) ? (w1_mb ? 0.5f : 0.0f)
                                     : (1.0f + w1_mb * 0.5f) * (float)(1 << (w1_eb - 1));
        float w1_val = (w1_sign ? -w1_base : w1_base) * exp2f((float)w1_exp - 127.0f);
