                                     : (1.0f + w2_mb * 0.5f) * (float)(1 << (w2_eb - 1));
        float w2_val = (w2_sign ? -w2_base : w2_base) * exp2f((float)w2_exp - 127.0f);
        float b2_val = expert_b2[expert_idx];
            float h_val = w1_val * gru_new + b1_val;
